const Challenges = () => {
    const challengeData = [
        { id: 1, title: "Route Optimization", img: "https://via.placeholder.com/300x200?text=Traffic+Logic", desc: "Avoiding city congestion." },
        { id: 2, title: "Inventory Accuracy", img: "https://via.placeholder.com/300x200?text=Stock+Control", desc: "Real-time shelf tracking." },
        { id: 3, title: "Waste Reduction", img: "https://via.placeholder.com/300x200?text=Expiry+Alerts", desc: "Perishable item management." },
        { id: 4, title: "Fast Dispatch", img: "https://via.placeholder.com/300x200?text=Quick+Delivery", desc: "Beating delivery deadlines." },
    ];

    return (
        <div style={{ padding: '40px 20px', backgroundColor: '#fff' }}>
            <h2 style={{ textAlign: 'center', marginBottom: '30px' }}>Core Business Challenges</h2>
            <div style={{ display: 'flex', gap: '20px', justifyContent: 'space-around', flexWrap: 'wrap' }}>
                {challengeData.map((item) => (
                    <div key={item.id} style={{ width: '250px', textAlign: 'center' }}>
                        <img
                            src={item.img}
                            alt={item.title}
                            style={{ width: '100%', borderRadius: '15px', boxShadow: '0 4px 8px rgba(0,0,0,0.1)' }}
                        />
                        <h4 style={{ marginTop: '15px' }}>{item.title}</h4>
                        <p style={{ fontSize: '14px', color: '#666' }}>{item.desc}</p>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default Challenges;
